script:
frappe.call('atlas.atlas.api.workspace.bootstrap_status').then((r) => {
    if (!r || !r.message) return;
    const counts = r.message;
    const root = root_element.querySelector('.atlas-bootstrap-checklist');
    if (!root) return;

    const dismissed = (frappe.boot.user.defaults || {}).atlas_bootstrap_dismissed === '1';
    const total = Object.keys(counts).length;
    const done = Object.values(counts).filter((n) => n > 0).length;

    if (dismissed && done === total) {
        root.style.display = 'none';
        return;
    }

    root.style.display = '';

    root.querySelectorAll('li[data-step]').forEach((li) => {
        const step = li.dataset.step;
        const satisfied = (counts[step] || 0) > 0;
        li.classList.toggle('done', satisfied);
        const mark = li.querySelector('.atlas-bsc-mark');
        if (mark) mark.textContent = satisfied ? '✓' : '○';
        const cta = li.querySelector('.atlas-bsc-cta');
        if (satisfied && cta) {
            const doctype = li.dataset.doctype;
            cta.textContent = `Open ${doctype}`;
            cta.setAttribute('href', `/app/${frappe.router.slug(doctype)}`);
        }
    });

    if (done === total) {
        let banner = root.querySelector('.atlas-bsc-complete');
        if (!banner) {
            banner = document.createElement('div');
            banner.className = 'atlas-bsc-complete';
            banner.textContent = 'Bootstrap complete ✓  All four steps are done.';
            root.appendChild(banner);
        }
    }

    const skip = root.querySelector('.atlas-bsc-skip');
    if (skip) {
        skip.onclick = () => {
            frappe.call({
                method: 'frappe.client.set_default',
                args: {key: 'atlas_bootstrap_dismissed', value: '1'},
            }).then(() => {
                root.style.display = 'none';
            });
        };
    }
});

style:
.atlas-bootstrap-checklist {
    border: 1px solid var(--border-color);
    border-radius: var(--border-radius-md);
    padding: 18px 20px;
    background: var(--bg-color);
    margin-bottom: 20px;
}
.atlas-bootstrap-checklist .atlas-bsc-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 12px;
}
.atlas-bootstrap-checklist .atlas-bsc-title {
    font-size: var(--text-lg);
    font-weight: 600;
}
.atlas-bootstrap-checklist .atlas-bsc-steps {
    list-style: none;
    padding: 0;
    margin: 0;
}
.atlas-bootstrap-checklist .atlas-bsc-steps li {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 6px 0;
    color: var(--text-color);
}
.atlas-bootstrap-checklist .atlas-bsc-steps li.done .atlas-bsc-label {
    color: var(--text-muted);
    text-decoration: line-through;
}
.atlas-bootstrap-checklist .atlas-bsc-mark {
    width: 18px;
    text-align: center;
    color: var(--green-500, #28a745);
    font-weight: 700;
}
.atlas-bootstrap-checklist li:not(.done) .atlas-bsc-mark {
    color: var(--text-muted);
}
.atlas-bootstrap-checklist .atlas-bsc-label {
    flex: 1;
}
.atlas-bootstrap-checklist .atlas-bsc-cta {
    font-size: var(--text-sm);
}
.atlas-bootstrap-checklist .atlas-bsc-cli {
    margin-top: 12px;
    padding-top: 10px;
    border-top: 1px dashed var(--border-color);
    color: var(--text-muted);
    font-size: var(--text-sm);
}
.atlas-bootstrap-checklist .atlas-bsc-cli code {
    background: var(--fg-color);
    padding: 1px 6px;
    border-radius: 4px;
}
.atlas-bootstrap-checklist .atlas-bsc-complete {
    margin-top: 10px;
    color: var(--green-500, #28a745);
    font-weight: 500;
}
